        content: "```cpp\n#include <mutex>\n#include <condition_variable>\n#include <queue>\n\nstd::queue<int> buffer;\nstd::mutex mtx;\nstd::condition_variable cv;\nconstexpr int MAX_SIZE = 10;\n\nvoid producer(int n) {\n    for (int i = 0; i < n; i++) {\n        std::unique_lock<std::mutex> lock(mtx);\n        cv.wait(lock, []{ return buffer.size() < MAX_SIZE; });\n        buffer.push(i);\n        std::cout << \"Produs: \" << i << \"\\n\";\n        cv.notify_all();\n    }\n}\n\nvoid consumer(int n) {\n    for (int i = 0; i < n; i++) {\n        std::unique_lock<std::mutex> lock(mtx);\n        cv.wait(lock, []{ return !buffer.empty(); });\n        int val = buffer.front();\n        buffer.pop();\n        std::cout << \"Consumat: \" << val << \"\\n\";\n        cv.notify_all();\n    }\n}\n\nint main() {\n    std::thread prod(producer, 5);\n    std::thread cons(consumer, 5);\n    prod.join(); cons.join();\n}\n```"
